const cfg   = $('Config').first().json;
const items = $('Fetch Pending Call Queue').all();

if (!items.length || !items[0].json?.id) {
  return [{ json: { dispatched: 0 } }];
}

const results = [];

for (const item of items) {
  const entry = item.json;
  if (!entry?.id) continue;

  // Skip if max attempts reached
  if (entry.attempt > entry.max_attempts) {
    await fetch(
      `${cfg.SUPABASE_URL}/rest/v1/call_queue?id=eq.${entry.id}`,
      {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          'apikey': cfg.SUPABASE_SERVICE_KEY,
          'Authorization': `Bearer ${cfg.SUPABASE_SERVICE_KEY}`,
          'Prefer': 'return=minimal',
        },
        body: JSON.stringify({ status: 'failed' }),
      }
    );
    continue;
  }

  // Update call_queue to 'dialing'
  await fetch(
    `${cfg.SUPABASE_URL}/rest/v1/call_queue?id=eq.${entry.id}`,
    {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json',
        'apikey': cfg.SUPABASE_SERVICE_KEY,
        'Authorization': `Bearer ${cfg.SUPABASE_SERVICE_KEY}`,
        'Prefer': 'return=minimal',
      },
      body: JSON.stringify({ status: 'dialing' }),
    }
  );

  // POST to process-trigger with event='no_answer'
  const body = JSON.stringify({
    event:  'no_answer',
    org_id: entry.organization_id,
    ref_id: entry.run_id,
    data: {
      call_queue_id: entry.id,
      attempt:       entry.attempt,
      script_type:   entry.script_type,
      phone:         entry.phone,
    },
  });

  try {
    const res = await fetch(`${cfg.DASHBOARD_URL}/api/workflows/process-trigger`, {
      method:  'POST',
      headers: {
        'Content-Type':       'application/json',
        'x-internal-secret':  cfg.INTERNAL_SECRET,
      },
      body,
    });
    const result = await res.json();
    results.push({ json: { entry_id: entry.id, org_id: entry.organization_id, result } });
  } catch(e) {
    console.error('Failed to dispatch retry for call_queue:', entry.id, e);
    // Revert status to pending for retry
    await fetch(
      `${cfg.SUPABASE_URL}/rest/v1/call_queue?id=eq.${entry.id}`,
      {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
          'apikey': cfg.SUPABASE_SERVICE_KEY,
          'Authorization': `Bearer ${cfg.SUPABASE_SERVICE_KEY}`,
          'Prefer': 'return=minimal',
        },
        body: JSON.stringify({ status: 'pending' }),
      }
    );
    results.push({ json: { entry_id: entry.id, error: String(e) } });
  }
}

return results.length ? results : [{ json: { dispatched: 0 } }];
